// Make ICD11_CODES available globally
window.ICD11_CODES = ICD11_CODES;

// Search function for ICD-11 codes
function searchLocalCodes(query) {
  if (!query || query.length < 2) {
    return [];
  }
  
  const searchTerm = query.toLowerCase();
  return ICD11_CODES.filter(item => 
    item.title.toLowerCase().includes(searchTerm) || 
    item.code.toLowerCase().includes(searchTerm)
  ).slice(0, 10); // Limit to 10 results for performance
}

// Make search function available globally
window.searchLocalCodes = searchLocalCodes;

console.log('ICD-11 search function loaded. Total codes:', ICD11_CODES.length);
